import java.io.IOException;
import java.io.PrintWriter;

import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handle user input by escaping it before including in the HTML response
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<head><title>XSS Secure Page</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome, " + escapedUserInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        // Now, the user input is properly escaped and safe to include in the HTML response
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
